func TestMCPServerInitializesAndListsRuntimeTools(t *testing.T) {
	s := server.NewMCPServer(
		"Amazon Ads",
		"1.0.0",
		server.WithToolCapabilities(false),
	)
	RegisterTools(s)

	initResponse := s.HandleMessage(context.Background(), []byte(`{
		"jsonrpc": "2.0",
		"id": 1,
		"method": "initialize",
		"params": {
			"protocolVersion": "2024-11-05",
			"capabilities": {},
			"clientInfo": {
				"name": "amazon-ads-pp-cli-test",
				"version": "0.0.0"
			}
		}
	}`))
	initRPC, ok := initResponse.(mcplib.JSONRPCResponse)
	if !ok {
		t.Fatalf("initialize response type = %T, want JSONRPCResponse", initResponse)
	}
	initResult, ok := initRPC.Result.(mcplib.InitializeResult)
	if !ok {
		t.Fatalf("initialize result type = %T, want InitializeResult", initRPC.Result)
	}
	if initResult.ServerInfo.Name != "Amazon Ads" {
		t.Fatalf("server name = %q, want Amazon Ads", initResult.ServerInfo.Name)
	}
	if initResult.Capabilities.Tools == nil {
		t.Fatal("initialize result did not advertise tool capability")
	}

	if response := s.HandleMessage(context.Background(), []byte(`{
		"jsonrpc": "2.0",
		"method": "notifications/initialized"
	}`)); response != nil {
		t.Fatalf("initialized notification response = %#v, want nil", response)
	}

	listResponse := s.HandleMessage(context.Background(), []byte(`{
		"jsonrpc": "2.0",
		"id": 2,
		"method": "tools/list"
	}`))
	listRPC, ok := listResponse.(mcplib.JSONRPCResponse)
	if !ok {
		t.Fatalf("tools/list response type = %T, want JSONRPCResponse", listResponse)
	}
	listResult, ok := listRPC.Result.(mcplib.ListToolsResult)
	if !ok {
		t.Fatalf("tools/list result type = %T, want ListToolsResult", listRPC.Result)
	}

	tools := map[string]mcplib.Tool{}
	for _, tool := range listResult.Tools {
		tools[tool.Name] = tool
	}
	for _, name := range []string{
		"amazon-ads_search",
		"amazon-ads_execute",
		"context",
		"search",
		"sql",
		"portfolio_dashboard",
		"reports_wait",
		"auto_negate",
	} {
		if _, ok := tools[name]; !ok {
			t.Fatalf("tools/list missing %q", name)
		}
	}

	autoNegate := tools["auto_negate"]
	if autoNegate.Annotations.ReadOnlyHint == nil || *autoNegate.Annotations.ReadOnlyHint {
		t.Fatal("auto_negate must be registered as non-read-only")
	}
	if autoNegate.Annotations.DestructiveHint == nil || !*autoNegate.Annotations.DestructiveHint {
		t.Fatal("auto_negate must be registered as destructive")
	}
	if autoNegate.Annotations.OpenWorldHint == nil || !*autoNegate.Annotations.OpenWorldHint {
		t.Fatal("auto_negate must be registered as open-world")
	}
}
